(window.webpackJsonp=window.webpackJsonp||[]).push([[1366],{1661:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for an interval.\\n * function Interval(start, end) {\\n *     this.start = start;\\n *     this.end = end;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{Interval[]}</span> <span class=\\"hljs-variable\\">A</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{Interval[]}</span> <span class=\\"hljs-variable\\">B</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{Interval[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> intervalIntersection = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">A, B</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;A.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> a=A[i]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;B.length;j++){\\n      <span class=\\"hljs-keyword\\">let</span> b=B[j]\\n      <span class=\\"hljs-keyword\\">if</span>(b.end&lt;a.start)<span class=\\"hljs-keyword\\">continue</span>\\n      <span class=\\"hljs-keyword\\">let</span> inte=hasInterv(a,b)\\n      <span class=\\"hljs-keyword\\">if</span>(inte){\\n        res.push(inte)\\n      }<span class=\\"hljs-keyword\\">else</span>{\\n        <span class=\\"hljs-keyword\\">break</span>\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">hasInterv</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> intS=<span class=\\"hljs-built_in\\">Math</span>.max(a.start,b.start)\\n    <span class=\\"hljs-keyword\\">let</span> intE=<span class=\\"hljs-built_in\\">Math</span>.min(a.end,b.end)\\n    <span class=\\"hljs-keyword\\">if</span>(intS&lt;=intE)<span class=\\"hljs-keyword\\">return</span> {<span class=\\"hljs-attr\\">start</span>:intS,<span class=\\"hljs-attr\\">end</span>:intE}\\n    <span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">null</span>\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"interval-list-intersections","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e24\u4e2a\u7531\u4e00\u4e9b<strong> \u95ed\u533a\u95f4 </strong>\u7ec4\u6210\u7684\u5217\u8868\uff0c<code>firstList</code> \u548c <code>secondList</code> \uff0c\u5176\u4e2d <code>firstList[i] = [start<sub>i</sub>, end<sub>i</sub>]</code> \u800c\xa0<code>secondList[j] = [start<sub>j</sub>, end<sub>j</sub>]</code> \u3002\u6bcf\u4e2a\u533a\u95f4\u5217\u8868\u90fd\u662f\u6210\u5bf9 <strong>\u4e0d\u76f8\u4ea4</strong> \u7684\uff0c\u5e76\u4e14 <strong>\u5df2\u7ecf\u6392\u5e8f</strong> \u3002</p>\\n\\n<p>\u8fd4\u56de\u8fd9 <strong>\u4e24\u4e2a\u533a\u95f4\u5217\u8868\u7684\u4ea4\u96c6</strong> \u3002</p>\\n\\n<p>\u5f62\u5f0f\u4e0a\uff0c<strong>\u95ed\u533a\u95f4</strong>\xa0<code>[a, b]</code>\uff08\u5176\u4e2d\xa0<code>a <= b</code>\uff09\u8868\u793a\u5b9e\u6570\xa0<code>x</code>\xa0\u7684\u96c6\u5408\uff0c\u800c\xa0<code>a <= x <= b</code> \u3002</p>\\n\\n<p>\u4e24\u4e2a\u95ed\u533a\u95f4\u7684 <strong>\u4ea4\u96c6</strong> \u662f\u4e00\u7ec4\u5b9e\u6570\uff0c\u8981\u4e48\u4e3a\u7a7a\u96c6\uff0c\u8981\u4e48\u4e3a\u95ed\u533a\u95f4\u3002\u4f8b\u5982\uff0c<code>[1, 3]</code> \u548c <code>[2, 4]</code> \u7684\u4ea4\u96c6\u4e3a <code>[2, 3]</code> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2019/01/30/interval1.png\\" style=\\"width: 700px; height: 194px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>firstList = [[0,2],[5,10],[13,23],[24,25]], secondList = [[1,5],[8,12],[15,24],[25,26]]\\n<strong>\u8f93\u51fa\uff1a</strong>[[1,2],[5,5],[8,10],[15,23],[24,24],[25,25]]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>firstList = [[1,3],[5,9]], secondList = []\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>firstList = [], secondList = [[4,8],[10,12]]\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>firstList = [[1,7]], secondList = [[3,10]]\\n<strong>\u8f93\u51fa\uff1a</strong>[[3,7]]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= firstList.length, secondList.length <= 1000</code></li>\\n\\t<li><code>firstList.length + secondList.length >= 1</code></li>\\n\\t<li><code>0 <= start<sub>i</sub> < end<sub>i</sub> <= 10<sup>9</sup></code></li>\\n\\t<li><code>end<sub>i</sub> < start<sub>i+1</sub></code></li>\\n\\t<li><code>0 <= start<sub>j</sub> < end<sub>j</sub> <= 10<sup>9</sup> </code></li>\\n\\t<li><code>end<sub>j</sub> < start<sub>j+1</sub></code></li>\\n</ul>\\n","title":"986. \u533a\u95f4\u5217\u8868\u7684\u4ea4\u96c6","relatedTags":["\u53cc\u6307\u9488"],"difficult":"Middle","lang":["javascript"],"uniqueID":"986"}')}}]);